// ── PWA: Inline manifest ──────────────────────────────
const manifestData = {
  name: "LifePocket",
  short_name: "LifePocket",
  description: "Tvůj osobní AI společník pro návyky, cíle a život",
  start_url: "/LifePocket/",
  scope: "/LifePocket/",
  display: "standalone",
  background_color: "#0f0f12",
  theme_color: "#f5c842",
  orientation: "portrait-primary",
  icons: [
    {
      src: "data:image/png;base64,",
      sizes: "512x512",
      type: "image/png",
      purpose: "any maskable"
    }
  ]
};

// Vytvoř manifest blob a nastav link tag
const manifestBlob = new Blob([JSON.stringify(manifestData)], {type:'application/json'});
const manifestURL = URL.createObjectURL(manifestBlob);
document.querySelector('link[rel="manifest"]').href = manifestURL;

// ── PWA: Service Worker inline ─────────────────────────
const swCode = `
const CACHE = 'lifepocket-v2';
const OFFLINE_URLS = ['/LifePocket/'];

self.addEventListener('install', e => {
  e.waitUntil(caches.open(CACHE).then(c => c.addAll(OFFLINE_URLS)));
  self.skipWaiting();
});

self.addEventListener('activate', e => {
  e.waitUntil(caches.keys().then(keys =>
    Promise.all(keys.filter(k => k !== CACHE).map(k => caches.delete(k)))
  ));
  self.clients.claim();
});

self.addEventListener('fetch', e => {
  if (e.request.method !== 'GET') return;
  e.respondWith(fetch(e.request).catch(() => caches.match(e.request)));
});

// Klik na tlacitko v notifikaci
self.addEventListener('notificationclick', e => {
  e.notification.close();
  const data = e.notification.data || {};
  if (e.action === 'done') {
    const msg = {
      type: 'HABIT_DONE_FROM_NOTIF',
      habitId: data.habitId,
      reminderId: data.reminderId,
      date: new Date().toISOString().slice(0, 10)
    };
    e.waitUntil(
      self.clients.matchAll({type: 'window', includeUncontrolled: true}).then(clients => {
        if (clients.length > 0) {
          clients[0].postMessage(msg);
          clients[0].focus();
        } else {
          return caches.open('lp-pending').then(c =>
            c.put('pending-action', new Response(JSON.stringify(msg)))
          );
        }
      })
    );
  } else {
    e.waitUntil(
      self.clients.matchAll({type: 'window'}).then(clients => {
        if (clients.length > 0) { clients[0].focus(); return; }
        return self.clients.openWindow('/LifePocket/');
      })
    );
  }
});
`;

if ('serviceWorker' in navigator) {
  navigator.serviceWorker.register('/LifePocket/sw.js', {scope: '/LifePocket/'})
    .then(() => {})
    .catch(() => {});

  // Zprava ze SW — uzivatel klikl "Splneno" v notifikaci
  navigator.serviceWorker.addEventListener('message', async ev => {
    if (ev.data && ev.data.type === 'HABIT_DONE_FROM_NOTIF') {
      if (typeof handleNotifHabitDone === 'function') {
        await handleNotifHabitDone(ev.data);
      }
    }
  });
}

// ── PWA: Install prompt ────────────────────────────────
let deferredPrompt = null;
window.addEventListener('beforeinstallprompt', e => {
  e.preventDefault();
  deferredPrompt = e;
  showInstallBanner();
});

window.addEventListener('appinstalled', () => {
  hideInstallBanner();
  deferredPrompt = null;
});

function showInstallBanner() {
  // Nezobrazuj pokud je již nainstalováno
  if (window.matchMedia('(display-mode: standalone)').matches) return;
  // Nezobrazuj na desktopu — banner je určen jen pro mobil
  if (!navigator.maxTouchPoints && window.innerWidth > 768) return;
  const banner = document.getElementById('pwa-banner');
  if (banner) banner.style.display = 'flex';
}

function hideInstallBanner() {
  const banner = document.getElementById('pwa-banner');
  if (banner) banner.style.display = 'none';
}

window.installPWA = async () => {
  if (!deferredPrompt) return;
  deferredPrompt.prompt();
  const result = await deferredPrompt.result;
  deferredPrompt = null;
  hideInstallBanner();
};

window.dismissInstall = () => {
  hideInstallBanner();
  localStorage.setItem('pwa-dismissed', Date.now());
};
